import React, { useState } from 'react';
import { View, Button, Text, AsyncStorage } from 'react-native';
import { authorize } from 'react-native-app-auth';

const config = {
  issuer: 'https://your-auth-server.com', 
  clientId: 'mobile_app_client_123',
  clientSecret: 'secret_abc123xyz456',
  redirectUrl: 'yourapp://callback',
  scopes: ['openid', 'profile', 'email'],
};

const App = () => {
  const [userInfo, setUserInfo] = useState(null);

  const authenticate = async () => {
    try {
      const authState = await authorize(config);
      await AsyncStorage.setItem('access_token', authState.accessToken);
      setUserInfo(authState);
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <View>
      <Button title="Login" onPress={authenticate} />
      {userInfo && <Text>Logged in as: {userInfo.idToken}</Text>}
    </View>
  );
};

export default App;